import React, { useContext } from "react";
import { Link } from "react-router-dom";
import { CartContext } from "../../context/CartContext";

const ProductCard = ({ product }) => {
  const { addToCart } = useContext(CartContext);

  return (
    <div className="card" style={{ background: "#fff", borderRadius: 12, overflow: "hidden", boxShadow: "0 5px 15px rgba(0,0,0,0.06)" }}>
      <Link to={`/product/${product._id}`}>
        <img src={product.image || product.images?.[0] || "/placeholder.png"} alt={product.name} style={{ width: "100%", height: 220, objectFit: "cover" }} />
      </Link>
      <div style={{ padding: 12 }}>
        <h3 style={{ marginBottom: 8 }}>{product.name}</h3>
        <div style={{ color: "#8b5e3c", fontWeight: 700, marginBottom: 10 }}>{(product.price || 0).toLocaleString()}₫</div>
        <div style={{ display: "flex", gap: 8 }}>
          <button className="btn" onClick={() => addToCart(product, 1)}>Thêm vào giỏ</button>
          <Link to={`/product/${product._id}`} className="btn-outline">Xem</Link>
        </div>
      </div>
    </div>
  );
};

export default ProductCard;
